<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Models\DailyReport;use Illuminate\Http\Request;
class DailyReportReviewController extends Controller{use Concerns;public function index(){ $this->requirePerm('tenant.daily_reports.review');return view('tenant.daily-reports.review',['reports'=>DailyReport::with('user')->whereIn('status',['submitted','reviewed'])->latest('submitted_at')->paginate(15)]);}public function show(DailyReport $dailyReport){$this->requirePerm('tenant.daily_reports.review');return view('tenant.daily-reports.show',['report'=>$dailyReport->load('items.task','user','reviewer')]);}public function approve(Request $r,DailyReport $dailyReport){$this->requirePerm('tenant.daily_reports.approve');$d=$r->validate(['review_comment'=>'nullable|string','quality_score'=>'nullable|integer|min:1|max:10']);$dailyReport->update($d+['status'=>'approved','reviewed_by'=>$r->user()->id,'reviewed_at'=>now()]);return back();}public function reject(Request $r,DailyReport $dailyReport){$this->requirePerm('tenant.daily_reports.reject');$d=$r->validate(['review_comment'=>'required|string','quality_score'=>'nullable|integer|min:1|max:10']);$dailyReport->update($d+['status'=>'rejected','reviewed_by'=>$r->user()->id,'reviewed_at'=>now()]);return back();}}
